type PhraseSeed = [icon: string, title: string, meaning: string, bullets: string[], close: string];
type SectionSeed = [chapter: number, startVerse: number, endVerse: number, title: string, icon: string, phrases: PhraseSeed[]];

const note = (lines: string[]) => lines.join("\n\n");

function phrase([icon, title, meaning, bullets, close]: PhraseSeed): [string, string] {
  return [
    `${icon} ${title}`,
    note([
      meaning,
      ...bullets,
      close,
    ]),
  ];
}

function section([chapter, startVerse, endVerse, title, icon, phrases]: SectionSeed): PersonalLeviticusPhraseSectionInput {
  return {
    chapter,
    startVerse,
    endVerse,
    reference: `1 Samuel ${chapter}:${startVerse}-${endVerse}`,
    title,
    icon,
    phrases: phrases.map(phrase),
  };
}

const p = (icon: string, title: string, meaning: string, bullets: string[], close: string): PhraseSeed => [icon, title, meaning, bullets, close];

